import './index.css';

import {
  Link
} from 'react-router-dom';

function Sidebar() {

  return (

    <div className="sidebar">

      <h2>
        Dashboard
      </h2>

      <Link to="/teacher-dashboard">
        Teacher
      </Link>

      <Link to="/student-dashboard">
        Student
      </Link>

      <Link to="/coordinator-dashboard">
        Coordinator
      </Link>

      <Link to="/subjects">
        Subjects
      </Link>

    </div>

  );

}

export default Sidebar;
